// Citizen is the themed skin the site is built around (downloaded into
// skins/Citizen by the deploy workflow). Vector is kept loaded as a
// fallback users can still select via preferences.
wfLoadSkin( 'Citizen' );
wfLoadSkin( 'Vector' );

// --- Extensions ------------------------------------------------------------
// Bundled with MediaWiki core; required for imported Spring wiki content to
// render (its templates use {{#if:}} etc., pages use <ref> and code blocks).
wfLoadExtension( 'ParserFunctions' );
wfLoadExtension( 'Cite' );
wfLoadExtension( 'SyntaxHighlight_GeSHi' );

// DynamicPageList3 powers the live Recent-changes list on the Main Page via
// {{#dpl:}} (downloaded into extensions/DynamicPageList3 by the workflow).
wfLoadExtension( 'DynamicPageList3' );

// Bundled with core; used by imported Zero-K wiki content (category browsing,
// clickable map images, inline search boxes in templates).
wfLoadExtension( 'CategoryTree' );
wfLoadExtension( 'ImageMap' );
wfLoadExtension( 'InputBox' );

// Scribunto: executes the Lua modules (Module: namespace) that back the
// imported Zero-K wiki's infobox/formatting templates (downloaded into
// extensions/Scribunto by the workflow). Needs an actual Lua interpreter —
// the DreamHost account has none installed and no compiler access reliable
// enough to build one there, so the deploy workflow cross-compiles a static
// Lua 5.1.5 binary on the runner (portable across glibc versions since it's
// statically linked) and ships it to ~/lua-bin/lua5.1, OUTSIDE the web docroot
// so it's never web-servable. LocalSettings.php lives at the docroot root, so
// dirname(__DIR__) is the account's home directory.
wfLoadExtension( 'Scribunto' );
$wgScribuntoDefaultEngine = 'luastandalone';
$wgScribuntoEngineConf['luastandalone']['luaPath'] = dirname( __DIR__ ) . '/lua-bin/lua5.1';

// --- Anti-spam: CAPTCHA on account creation --------------------------------
// ConfirmEdit + QuestyCaptcha (both bundled with core). QuestyCaptcha asks a
// custom question only a human RTS player can answer — no external service,
// no API keys — which stops the generic sign-up bots. Registered users skip
// it entirely; anonymous account creation and anon link-adding are gated.
wfLoadExtension( 'ConfirmEdit' );
wfLoadExtension( 'ConfirmEdit/QuestyCaptcha' );
$wgCaptchaClass = 'MediaWiki\\Extension\\ConfirmEdit\\QuestyCaptcha\\QuestyCaptcha';

// Answers are matched case-insensitively; one question is chosen at random.
$wgCaptchaQuestions = [
	'This wiki is named after the RTS order that makes a unit move and attack anything in its path. What is that one-word command?' => [ 'fight' ],
	'In Spring/Recoil economies, what resource do Metal Extractors pull from the ground? (one word)' => [ 'metal' ],
	'What engine is Beyond All Reason built on? (one word)' => [ 'recoil' ],
	'Type the number that comes after four (as a word).' => [ 'five' ],
	'What is 3 + 4? (write the number as digits)' => [ '7' ],
];

// Only gate the actions bots abuse; never gate ordinary logged-in editing.
$wgCaptchaTriggers['createaccount'] = true;   // the fix: sign-up needs a human
$wgCaptchaTriggers['badlogin']      = true;   // slows credential-stuffing
$wgCaptchaTriggers['addurl']        = true;   // anon adding external links (spam)
$wgCaptchaTriggers['edit']          = false;
$wgCaptchaTriggers['create']        = false;

// Registered, confirmed users never see a CAPTCHA.
$wgGroupPermissions['*']['skipcaptcha']    = false;
$wgGroupPermissions['user']['skipcaptcha'] = true;

